from kafka import KafkaConsumer
import json
import pickle
from typing import Dict, Any

class FinancialTransactionConsumer:
    def __init__(self, bootstrap_servers: str, topic: str):
        self.consumer = KafkaConsumer(topic, bootstrap_servers=bootstrap_servers, auto_offset_reset='earliest', value_deserializer=lambda m: pickle.load(m.value, encoding='bytes'))
        self.handlers = {}  # Dictionary to store message handlers

    def add_handler(self, event_type: str, handler: callable):
        """ Adds a new message handler for the specified event type."""
        self.handlers[event_type] = handler

    def run(self):
        for message in self.consumer:
            event = json.loads(message.value)  # Assuming the serialized data is in JSON format
            if event['event_type'] in self.handlers:
                self.handlers[event['event_type']](event)

    def start(self):
        self.run()